update_post_meta($post_id, 'featured_image_caption', 'Bound Caption');
$registry = WP_Block_Bindings_Registry::get_instance();
$source = method_exists( $registry, 'get_registered' ) ? $registry->get_registered('myplugin/meta-caption') : null;
$callback = $source['get_value_callback'] ?? null;
$value = $callback ? call_user_func($callback, [], (object)['context' => ['postId' => $post_id]], 'caption') : null;
wp_delete_post($post_id, true);
