add_filter( 'block_bindings_supported_attributes_core/button', function( $attrs ) {
    if ( ! in_array( 'ariaLabel', $attrs, true ) ) {
        $attrs[] = 'ariaLabel';
    }
    return $attrs;
} );
add_filter( 'render_block', function( $content, $block ) {
    if ( ( $block['blockName'] ?? '' ) !== 'core/button' ) {
        return $content;
    }
    if ( empty( $block['attrs']['ariaLabel'] ) ) {
        return $content;
    }
    $aria = esc_attr( $block['attrs']['ariaLabel'] );
    // Ensure sanitized aria-label is present even if theme filters markup.
    if ( str_contains( $content, 'aria-label=' ) ) {
        return preg_replace( '/aria-label="[^"]*"/', 'aria-label="' . $aria . '"', $content );
    }
    return str_replace( '<a ', '<a aria-label="' . $aria . '" ', $content );
}, 10, 2 );
